def assess(record: dict) -> str:
    required = {'agent_success', 'baseline_success', 'branch_count', 'case_id', 'known_steps', 'tool_choice_uncertain'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (not (not record["known_steps"] or record["agent_success"] > record["baseline_success"])) else "KEEP_DETERMINISTIC_WORKFLOW"

valid = {"case_id": "CASO-AYA-049-1A", **{"known_steps":True,"branch_count":2,"tool_choice_uncertain":False,"baseline_success":0.96,"agent_success":0.9}}
invalid = {'case_id':'CASO-AYA-049-1A','known_steps':False,'branch_count':2,'tool_choice_uncertain':False,'baseline_success':0.96,'agent_success':0.9}
incomplete = {**valid}
incomplete.pop('agent_success')
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

